code = """import json, pandas as pd

# Load reviews
path_reviews = var_call_f24Y5LovsWqj0XenSmJDjFyI
with open(path_reviews, 'r') as f:
    reviews = json.load(f)

# Load business categories mapping
business_docs = var_call_YGmf5x6vhCzVmcS7Q4xKRmHM

# Build DataFrames
rev_df = pd.DataFrame(reviews)
# Extract business numeric id from business_ref_XX
rev_df['business_num'] = rev_df['business_ref'].str.replace('businessref_', '', regex=False)

biz_df = pd.DataFrame(business_docs)
# Some docs may not have categories; fill with empty string
if 'categories' not in biz_df.columns:
    biz_df['categories'] = ''

biz_df['business_num'] = biz_df['business_id'].str.replace('businessid_', '', regex=False)

# Merge on numeric id
merged = rev_df.merge(biz_df[['business_num','categories']], on='business_num', how='left')

# Split categories by comma and explode
merged['categories'] = merged['categories'].fillna('')
merged['categories_list'] = merged['categories'].apply(lambda x: [c.strip() for c in x.split(',') if c.strip()] if isinstance(x,str) else [])

exploded = merged.explode('categories_list')

# Count reviews per category
cat_counts = exploded.groupby('categories_list').size().reset_index(name='review_count')
cat_counts = cat_counts[cat_counts['categories_list'] != '']

# Get top 5
top5 = cat_counts.sort_values('review_count', ascending=False).head(5)

result = top5.to_dict(orient='records')
res_json = json.dumps(result)
print("__RESULT__:")
print(res_json)"""

